const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
};

interface Item {
  type: string;
}

interface QuoteStep {
  op: "quote";
  items: Item[];
}

interface Scenario {
  steps: QuoteStep[];
}

const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;

const sumBasePremiums = (items: Item[]): number =>
  items.reduce((total, item) => total + basePremiumFor(item), 0);

const quoteStep = (step: QuoteStep) => ({
  premium: sumBasePremiums(step.items) + PROCESSING_FEE,
});

export const runScenario = (input: unknown): unknown => {
  const scenario = input as Scenario;
  return { results: scenario.steps.map(quoteStep) };
};
